CREATE OR REPLACE FUNCTION fpb_get_comment ( as_table char , as_column char ) RETURNS varchar AS $body$
DECLARE

ls_comments user_col_comments.comments%type;
li_len bigint;

BEGIN

    select  right(  left( comments ,len( comments ) - 2 ) ,len( comments ) - 4 )
    into STRICT ls_comments
    from user_col_comments
    where lower(table_name) = as_table
    and lower(column_name) = as_column;

    RETURN ls_comments;
END;
$body$
LANGUAGE PLPGSQL
